#include <stdio.h>
#include <stdlib.h>
#define MAX_N 37
#define MAX_VOTES 37

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        double dp[MAX_N][MAX_VOTES];
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= n; j++) {
                dp[i][j] = 0.0;
            }
        }
        dp[1][1] = 1.0;
        for (int i = 2; i <= n; i++) {
            for (int j = 1; j <= i; j++) {
                for (int k = 1; k <= i; k++) {
                    if (k != j) {
                        dp[i][j] += (1.0 / (i - 1)) * dp[i - 1][k];
                    }
                }
            }
        }
        double max_votes = 0.0;
        for (int j = 1; j <= n; j++) {
            if (dp[n][j] > max_votes) {
                max_votes = dp[n][j];
            }
        }
        double expected_presidents = 0.0;
        for (int j = 1; j <= n; j++) {
            if (dp[n][j] == max_votes) {
                expected_presidents += 1.0;
            }
        }
        printf("%.6f\n", expected_presidents);
    }
    return 0;
}

