const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const n = parseInt(readline());
    const dp = Array(n + 1).fill(0).map(() => Array(n + 1).fill(0.0));
    dp[1][1] = 1.0;
    for (let j = 2; j <= n; j++) {
        for (let k = 1; k <= j; k++) {
            for (let l = 1; l <= j; l++) {
                if (l !== k) {
                    dp[j][k] += (1.0 / (j - 1)) * dp[j - 1][l];
                }
            }
        }
    }
    let max_votes = 0.0;
    for (let k = 1; k <= n; k++) {
        if (dp[n][k] > max_votes) {
            max_votes = dp[n][k];
        }
    }
    let expected_presidents = 0.0;
    for (let k = 1; k <= n; k++) {
        if (dp[n][k] === max_votes) {
            expected_presidents += 1.0;
        }
    }
    console.log(expected_presidents.toFixed(6));
}
